/**
 * Public Strategy Page — Accessible without login.
 * Shows strategy summary + key metrics + CTA to sign up.
 * Route: /s/:strategyId
 */
import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { api } from '../utils/api';
import usePageTitle from '../hooks/usePageTitle';
import AhaMomentPanel from '../components/AhaMomentPanel';
import s from './PublicStrategyPage.module.css';

export default function PublicStrategyPage() {
  const { strategyId } = useParams();
  const nav = useNavigate();
  usePageTitle(`Strategy: ${strategyId}`);
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api(`/api/economy/strategy/${strategyId}`).then(d => { if (d) setData(d); setLoading(false); });
  }, [strategyId]);

  if (loading) return (
    <div className={s.loadingWrap}>
      <span className={s.loadingText}>Loading...</span>
    </div>
  );

  if (!data) return (
    <div className={s.notFoundWrap}>
      <div className={s.notFoundText}>Strategy not found or not yet published.</div>
      <button onClick={() => nav('/landing')} className={s.notFoundBtn}>
        Explore Aura Alpha
      </button>
    </div>
  );

  return (
    <div className={s.shell}>
      {/* Branding header */}
      <div className={s.header}>
        <div onClick={() => nav('/landing')} className={s.brand}>
          <span className={s.brandName}>AURA ALPHA</span>
          <span className={s.brandTag}>AI Quant Research OS</span>
        </div>
        <button onClick={() => nav('/register')} className={s.signUpBtn}>Sign Up Free</button>
      </div>

      <div className={s.content}>
        {/* Strategy header */}
        <div className={s.stratHeader}>
          <div className={s.overviewLabel}>STRATEGY OVERVIEW</div>
          <h1 className={s.stratTitle}>
            {data.title || strategyId}
          </h1>
          <div className={s.stratMeta}>
            {data.family} · {data.direction} · {data.risk_level || 'medium'} risk
          </div>
          {data.summary && <p className={s.stratSummary}>{data.summary}</p>}
        </div>

        {/* Key metrics */}
        <div className={s.metricsGrid}>
          {[
            { label: 'Alpha Score', value: (data.alpha_score || 0).toFixed(2), color: data.alpha_score >= 0.7 ? 'var(--color-green)' : undefined },
            { label: 'Sharpe', value: (data.sharpe || 0).toFixed(2) },
            { label: 'Profit Factor', value: (data.profit_factor || 0).toFixed(2) },
            { label: 'Max Drawdown', value: `${((data.max_drawdown || 0) * 100).toFixed(0)}%`, color: data.max_drawdown < -0.25 ? 'var(--color-red)' : undefined },
          ].map(m => (
            <div key={m.label} className={s.metricCard}>
              <div className={s.metricValue} style={m.color ? { color: m.color } : undefined}>{m.value}</div>
              <div className={s.metricLabel}>{m.label}</div>
            </div>
          ))}
        </div>

        {/* Aha moment */}
        <AhaMomentPanel strategy={data} />

        {/* Badges */}
        {data.badges?.length > 0 && (
          <div className={s.badges}>
            {data.badges.map(b => (
              <span key={b} className={s.badge}>
                {b.replace(/_/g, ' ').toUpperCase()}
              </span>
            ))}
          </div>
        )}

        {/* CTA */}
        <div className={s.ctaBlock}>
          <div className={s.ctaTitle}>
            View the full analysis on Aura Alpha
          </div>
          <div className={s.ctaSub}>
            Walk-forward validation, regime scoring, reputation tracking, and AI-powered insights.
          </div>
          <button onClick={() => nav('/register')} className={s.ctaBtn}>Start Free — See Full Analysis</button>
          <div className={s.ctaDisclaimer}>
            <span className={s.ctaDisclaimerText}>
              No automated trading · Research-only platform · Cancel anytime
            </span>
          </div>
        </div>
      </div>
    </div>
  );
}
